import java.util.List;

/**
 * A data class for storing parsed configuration information.
 */
public class ConfigFile {

    /**
     * The name of the function being tested.
     */
    private final String funcName;

    /**
     * The list of PyNodes representing the function's parameters.
     */
    private final List<APyNode<?>> nodes;

    /**
     * The number of random test cases to generate.
     */
    private final int numRand;

    /**
     * Constructor for a ConfigFile.
     *
     * @param funcName the name of the function being tested
     * @param nodes    the list of PyNodes representing the function's parameters
