package main.rice.parse;

import main.rice.node.*;
import org.json.JSONArray;
import org.json.JSONObject;

import java.util.*;
import java.util.regex.Pattern;

/**
 * A parser for JSON configuration files that validates structure and creates PyNodes.
 */
public class ConfigFileParser {

    /**
     * Parses a JSON configuration string and returns a ConfigFile object.
     *
     * @param jsonStr the JSON string to parse
     * @return a ConfigFile object with parsed configuration
     * @throws InvalidConfigException if the JSON is invalid or violates validation rules
     */
    public ConfigFile parse(String jsonStr) throws InvalidConfigException {
        // Parse JSON
        JSONObject json;
        try {
            json = new JSONObject(jsonStr);
        } catch (Exception e) {
            throw new InvalidConfigException("Invalid JSON: " + e.getMessage());
        }

        // Validate required fields exist and are correct types
        validateRequiredFields(json);

        // Extract fields
        String fname = json.getString("fname");
        JSONArray typesArr = json.getJSONArray("types");
        JSONArray exDomainArr = json.getJSONArray("exhaustive domain");
        JSONArray ranDomainArr = json.getJSONArray("random domain");
        int numRand = json.getInt("num random");

        // Validate field types and content
        validateFieldTypes(typesArr, exDomainArr, ranDomainArr, numRand);

        // Validate spurious characters
        validateSpuriousCharacters(typesArr, exDomainArr, ranDomainArr);

        // Parse types into a list of APyNode objects
        List<String> typeStrings = jsonArrayToStringList(typesArr);
        List<APyNode<?>> nodes = new ArrayList<>();
        for (String typeStr : typeStrings) {
            nodes.add(parseType(typeStr));
        }

        // Validate and set domains
        List<String> exDomainStrings = jsonArrayToStringList(exDomainArr);
        List<String> ranDomainStrings = jsonArrayToStringList(ranDomainArr);

        setDomains(nodes, typeStrings, exDomainStrings, ranDomainStrings);

        return new ConfigFile(fname, nodes, numRand);
    }

    /**
     * Validates that all required fields are present in the JSON.
     */
    private void validateRequiredFields(JSONObject json) throws InvalidConfigException {
        String[] requiredFields = {"fname", "types", "exhaustive domain", "random domain", "num random"};
        for (String field : requiredFields) {
            if (!json.has(field)) {
                throw new InvalidConfigException("Missing required field: " + field);
            }
        }
    }

    /**
     * Validates field types and basic constraints.
     */
    private void validateFieldTypes(JSONArray types, JSONArray exDomain, JSONArray ranDomain, int numRand)
            throws InvalidConfigException {
        // Check types array elements are strings
        for (int i = 0; i < types.length(); i++) {
            if (!(types.get(i) instanceof String)) {
                throw new InvalidConfigException("types array must contain only strings");
            }
        }

        // Check exhaustive domain array elements are strings
        for (int i = 0; i < exDomain.length(); i++) {
            if (!(exDomain.get(i) instanceof String)) {
                throw new InvalidConfigException("exhaustive domain array must contain only strings");
            }
        }

        // Check random domain array elements are strings
        for (int i = 0; i < ranDomain.length(); i++) {
            if (!(ranDomain.get(i) instanceof String)) {
                throw new InvalidConfigException("random domain array must contain only strings");
            }
        }

        // Check numRand is non-negative
        if (numRand < 0) {
            throw new InvalidConfigException("num random must be non-negative");
        }
    }

    /**
     * Validates that there are no spurious characters (parentheses, spaces, colons).
     */
    private void validateSpuriousCharacters(JSONArray types, JSONArray exDomain, JSONArray ranDomain)
            throws InvalidConfigException {
        for (int i = 0; i < types.length(); i++) {
            String typeStr = types.getString(i);
            validateTypeFormat(typeStr);
        }

        for (int i = 0; i < exDomain.length(); i++) {
            String domStr = exDomain.getString(i);
            validateDomainFormat(domStr);
        }

        for (int i = 0; i < ranDomain.length(); i++) {
            String domStr = ranDomain.getString(i);
            validateDomainFormat(domStr);
        }
    }

    /**
     * Validates type string format (no spurious characters).
     */
    private void validateTypeFormat(String typeStr) throws InvalidConfigException {
        // Check for spaces in inappropriate places
        if (typeStr.matches(".*\\w\\s+\\w.*")) {
            throw new InvalidConfigException("Type string contains spurious spaces: " + typeStr);
        }

        // Check for colons not used in dict syntax
        int colonCount = 0;
        for (int i = 0; i < typeStr.length(); i++) {
            if (typeStr.charAt(i) == ':') {
                colonCount++;
            }
        }
        // Colons should only appear in dict(K:V) format
        if (colonCount > 0) {
            // Validate that colons are properly placed in dict definitions
            if (!typeStr.contains("dict(") || !typeStr.contains(":")) {
                throw new InvalidConfigException("Invalid colon in type: " + typeStr);
            }
            // Check for trailing colons
            if (typeStr.endsWith(":") || typeStr.endsWith("):")) {
                throw new InvalidConfigException("Invalid colon in type: " + typeStr);
            }
        }

        // Check for mismatched parentheses
        validateParentheses(typeStr);
    }

    /**
     * Validates domain string format (no spurious characters).
     */
    private void validateDomainFormat(String domStr) throws InvalidConfigException {
        // Check for spaces around ~
        if (domStr.matches(".*\\d\\s*~\\s*\\d.*")) {
            if (domStr.contains(" ~ ") || domStr.contains("~ ") || domStr.contains(" ~")) {
                throw new InvalidConfigException("Domain string contains spurious spaces: " + domStr);
            }
        }

        // Check for colons
        if (domStr.contains(":")) {
            if (domStr.endsWith(":") || domStr.endsWith("):")) {
                throw new InvalidConfigException("Domain string contains spurious colon: " + domStr);
            }
            // Colons are only valid in dict domains like "0~2(1~3:[0, 1])"
        }

        // Check for mismatched parentheses
        validateParentheses(domStr);
    }

    /**
     * Validates that parentheses are balanced and properly formed.
     */
    private void validateParentheses(String str) throws InvalidConfigException {
        int count = 0;
        for (char c : str.toCharArray()) {
            if (c == '(') count++;
            else if (c == ')') count--;
            if (count < 0) {
                throw new InvalidConfigException("Mismatched parentheses: " + str);
            }
        }
        if (count != 0) {
            throw new InvalidConfigException("Mismatched parentheses: " + str);
        }
    }

    /**
     * Converts a JSONArray of strings to a List<String>.
     */
    private List<String> jsonArrayToStringList(JSONArray arr) throws InvalidConfigException {
        List<String> result = new ArrayList<>();
        for (int i = 0; i < arr.length(); i++) {
            result.add(arr.getString(i));
        }
        return result;
    }

    /**
     * Parses a type string and creates the appropriate PyNode.
     */
    private APyNode<?> parseType(String typeStr) throws InvalidConfigException {
        typeStr = typeStr.trim();

        if (typeStr.equals("bool")) {
            return new PyBoolNode();
        } else if (typeStr.equals("int")) {
            return new PyIntNode();
        } else if (typeStr.equals("float")) {
            return new PyFloatNode();
        } else if (typeStr.equals("str")) {
            return new PyStringNode();
        } else if (typeStr.startsWith("str(") && typeStr.endsWith(")")) {
            // str(abc) - the chars are the domain values
            return new PyStringNode();
        } else if (typeStr.startsWith("list(") && typeStr.endsWith(")")) {
            String innerType = typeStr.substring(5, typeStr.length() - 1);
            APyNode<?> innerNode = parseType(innerType);
            return new PyListNode<>(innerNode);
        } else if (typeStr.startsWith("tuple(") && typeStr.endsWith(")")) {
            String innerType = typeStr.substring(6, typeStr.length() - 1);
            APyNode<?> innerNode = parseType(innerType);
            return new PyTupleNode<>(innerNode);
        } else if (typeStr.startsWith("set(") && typeStr.endsWith(")")) {
            String innerType = typeStr.substring(4, typeStr.length() - 1);
            APyNode<?> innerNode = parseType(innerType);
            return new PySetNode<>(innerNode);
        } else if (typeStr.startsWith("dict(") && typeStr.endsWith(")")) {
            String innerTypes = typeStr.substring(5, typeStr.length() - 1);
            // Parse K:V from dict(K:V)
            int colonIdx = findDictColon(innerTypes);
            if (colonIdx == -1) {
                throw new InvalidConfigException("dict type must have K:V format: " + typeStr);
            }
            String keyType = innerTypes.substring(0, colonIdx);
            String valType = innerTypes.substring(colonIdx + 1);
            APyNode<?> keyNode = parseType(keyType);
            APyNode<?> valNode = parseType(valType);
            return new PyDictNode<>(keyNode, valNode);
        } else {
            throw new InvalidConfigException("Unknown type: " + typeStr);
        }
    }

    /**
     * Finds the position of the colon separating key and value types in a dict definition.
     * This needs to handle nested types correctly.
     */
    private int findDictColon(String innerTypes) {
        int depth = 0;
        for (int i = 0; i < innerTypes.length(); i++) {
            char c = innerTypes.charAt(i);
            if (c == '(') depth++;
            else if (c == ')') depth--;
            else if (c == ':' && depth == 0) {
                return i;
            }
        }
        return -1;
    }

    /**
     * Sets domains on nodes from domain specifications.
     */
    private void setDomains(List<APyNode<?>> nodes, List<String> typeStrings,
                           List<String> exDomainStrings, List<String> ranDomainStrings)
            throws InvalidConfigException {
        // Validate cardinality matches
        if (typeStrings.size() != exDomainStrings.size()) {
            throw new InvalidConfigException(
                String.format("Number of exhaustive domains (%d) doesn't match number of types (%d)",
                    exDomainStrings.size(), typeStrings.size())
            );
        }
        if (typeStrings.size() != ranDomainStrings.size()) {
            throw new InvalidConfigException(
                String.format("Number of random domains (%d) doesn't match number of types (%d)",
                    ranDomainStrings.size(), typeStrings.size())
            );
        }

        // Process each node-type-domain trio
        for (int i = 0; i < nodes.size(); i++) {
            APyNode<?> node = nodes.get(i);
            String typeStr = typeStrings.get(i);
            String exDomStr = exDomainStrings.get(i);
            String ranDomStr = ranDomainStrings.get(i);

            setDomain(node, typeStr, exDomStr, ranDomStr);
        }
    }

    /**
     * Sets domain on a single node with its type and domain strings.
     */
    private void setDomain(APyNode<?> node, String typeStr, String exDomStr, String ranDomStr)
            throws InvalidConfigException {
        List<Number> exVals = parseDomain(exDomStr, typeStr);
        List<Number> ranVals = parseDomain(ranDomStr, typeStr);

        node.setExDomain(exVals);
        node.setRanDomain(ranVals);

        // For container types, handle nested domains
        if (typeStr.startsWith("list(") || typeStr.startsWith("tuple(") || typeStr.startsWith("set(")) {
            String innerType = extractInnerType(typeStr);
            if (node instanceof AIterablePyNode) {
                APyNode<?> child = node.getLeftChild();
                if (child != null) {
                    // Parse nested domains
                    List<String> nestedEx = parseNestedDomain(exDomStr);
                    List<String> nestedRan = parseNestedDomain(ranDomStr);

                    if (nestedEx.size() != 1 || nestedRan.size() != 1) {
                        throw new InvalidConfigException("Container type expects exactly 1 nested domain");
                    }

                    setDomain(child, innerType, nestedEx.get(0), nestedRan.get(0));
                }
            }
        } else if (typeStr.startsWith("dict(")) {
            if (node instanceof PyDictNode) {
                APyNode<?> keyChild = node.getLeftChild();
                APyNode<?> valChild = node.getRightChild();

                if (keyChild != null && valChild != null) {
                    // Parse nested domains for key:value
                    List<String> nestedEx = parseNestedDomain(exDomStr);
                    List<String> nestedRan = parseNestedDomain(ranDomStr);

                    if (nestedEx.size() != 2 || nestedRan.size() != 2) {
                        throw new InvalidConfigException("dict type expects exactly 2 nested domains");
                    }

                    String keyType = extractDictKeyType(typeStr);
                    String valType = extractDictValType(typeStr);

                    setDomain(keyChild, keyType, nestedEx.get(0), nestedRan.get(0));
                    setDomain(valChild, valType, nestedEx.get(1), nestedRan.get(1));
                }
            }
        }
    }

    /**
     * Extracts the inner type from a container type like list(int) -> int.
     */
    private String extractInnerType(String typeStr) {
        int openParen = typeStr.indexOf('(');
        return typeStr.substring(openParen + 1, typeStr.length() - 1);
    }

    /**
     * Extracts the key type from dict(K:V).
     */
    private String extractDictKeyType(String typeStr) {
        int openParen = typeStr.indexOf('(');
        String inner = typeStr.substring(openParen + 1, typeStr.length() - 1);
        int colonIdx = findDictColon(inner);
        return inner.substring(0, colonIdx);
    }

    /**
     * Extracts the value type from dict(K:V).
     */
    private String extractDictValType(String typeStr) {
        int openParen = typeStr.indexOf('(');
        String inner = typeStr.substring(openParen + 1, typeStr.length() - 1);
        int colonIdx = findDictColon(inner);
        return inner.substring(colonIdx + 1);
    }

    /**
     * Parses nested domains from a domain string like "0~2(1~3)".
     * Returns a list of domain strings for nested containers.
     */
    private List<String> parseNestedDomain(String domStr) throws InvalidConfigException {
        List<String> result = new ArrayList<>();

        int parenIdx = domStr.indexOf('(');
        if (parenIdx == -1) {
            // No nested domain, which is invalid for container types
            throw new InvalidConfigException("Container type domain missing nested domain specification: " + domStr);
        }

        // Extract parts
        String outer = domStr.substring(0, parenIdx);
        String nested = domStr.substring(parenIdx + 1);
        if (nested.endsWith(")")) {
            nested = nested.substring(0, nested.length() - 1);
        }

        // Parse nested domains separated by semicolons for dict
        if (nested.contains(":")) {
            // Dict format: size(keyDomain:valDomain)
            int colonIdx = nested.indexOf(':');
            String keyPart = nested.substring(0, colonIdx);
            String valPart = nested.substring(colonIdx + 1);
            result.add(keyPart);
            result.add(valPart);
        } else {
            // Container format: size(elementDomain)
            result.add(nested);
        }

        return result;
    }

    /**
     * Parses a domain specification string into a list of numbers.
     * Handles range syntax (X~Y) and explicit values ([1, 2, 3]).
     */
    private List<Number> parseDomain(String domStr, String typeStr) throws InvalidConfigException {
        Set<Number> resultSet = new LinkedHashSet<>(); // LinkedHashSet to maintain order while removing dups

        // Remove outer parentheses if they exist (from nested)
        if (domStr.contains("(")) {
            int parenIdx = domStr.indexOf('(');
            domStr = domStr.substring(0, parenIdx);
        }

        // Check if it's explicit values like [1, 2, 3]
        if (domStr.startsWith("[") && domStr.endsWith("]")) {
            String inner = domStr.substring(1, domStr.length() - 1);
            if (inner.isEmpty()) {
                // Empty list
                return new ArrayList<>();
            }
            String[] parts = inner.split(",");
            for (String part : parts) {
                part = part.trim();
                Number val = parseNumber(part, typeStr);
                resultSet.add(val);
            }
        } else {
            // Range syntax X~Y
            if (!domStr.contains("~")) {
                throw new InvalidConfigException("Domain must be range (X~Y) or explicit values [a, b, c]: " + domStr);
            }

            String[] parts = domStr.split("~");
            if (parts.length != 2) {
                throw new InvalidConfigException("Invalid range syntax: " + domStr);
            }

            Number lower = parseNumber(parts[0].trim(), typeStr);
            Number upper = parseNumber(parts[1].trim(), typeStr);

            // Validate bounds
            if (lower.doubleValue() > upper.doubleValue()) {
                throw new InvalidConfigException("Lower bound exceeds upper bound: " + domStr);
            }

            // Generate range
            if (typeStr.equals("bool") || typeStr.equals("int")) {
                int start = lower.intValue();
                int end = upper.intValue();
                for (int i = start; i <= end; i++) {
                    resultSet.add(i);
                }
            } else if (typeStr.equals("float")) {
                // For floats, just add the endpoints
                resultSet.add(lower);
                resultSet.add(upper);
            } else if (typeStr.equals("str") || typeStr.startsWith("str(")) {
                // For strings, the domain is indices
                int start = lower.intValue();
                int end = upper.intValue();
                for (int i = start; i <= end; i++) {
                    resultSet.add(i);
                }
            } else if (typeStr.startsWith("list(") || typeStr.startsWith("tuple(") || typeStr.startsWith("set(")) {
                // For containers, the domain is size
                int start = lower.intValue();
                int end = upper.intValue();
                if (start < 0 || end < 0) {
                    throw new InvalidConfigException("Container size cannot be negative: " + domStr);
                }
                for (int i = start; i <= end; i++) {
                    resultSet.add(i);
                }
            } else if (typeStr.startsWith("dict(")) {
                // For dicts, the domain is size
                int start = lower.intValue();
                int end = upper.intValue();
                if (start < 0 || end < 0) {
                    throw new InvalidConfigException("Container size cannot be negative: " + domStr);
                }
                for (int i = start; i <= end; i++) {
                    resultSet.add(i);
                }
            }
        }

        // Validate domain values match type
        for (Number val : resultSet) {
            validateDomainValue(val, typeStr);
        }

        return new ArrayList<>(resultSet);
    }

    /**
     * Validates that a domain value matches its type.
     */
    private void validateDomainValue(Number val, String typeStr) throws InvalidConfigException {
        if (typeStr.equals("bool")) {
            int intVal = val.intValue();
            if (intVal != 0 && intVal != 1) {
                throw new InvalidConfigException("Bool values must be 0 or 1, got: " + intVal);
            }
        } else if (typeStr.equals("int")) {
            // Check if it's actually an integer
            if (val.doubleValue() != val.intValue()) {
                throw new InvalidConfigException("Int domain cannot contain non-integer values: " + val);
            }
        } else if (typeStr.equals("float")) {
            // Floats are OK
        } else if (typeStr.equals("str") || typeStr.startsWith("str(")) {
            // String domains are indices (integers)
            if (val.doubleValue() != val.intValue()) {
                throw new InvalidConfigException("String index domain must be integer: " + val);
            }
        } else if (typeStr.startsWith("list(") || typeStr.startsWith("tuple(") || typeStr.startsWith("set(")) {
            // Container size must be non-negative integer
            if (val.doubleValue() != val.intValue()) {
                throw new InvalidConfigException("Container size must be integer: " + val);
            }
            if (val.intValue() < 0) {
                throw new InvalidConfigException("Container size cannot be negative: " + val);
            }
        } else if (typeStr.startsWith("dict(")) {
            // Dict size must be non-negative integer
            if (val.doubleValue() != val.intValue()) {
                throw new InvalidConfigException("Dict size must be integer: " + val);
            }
            if (val.intValue() < 0) {
                throw new InvalidConfigException("Dict size cannot be negative: " + val);
            }
        }
    }

    /**
     * Parses a string into a Number.
     */
    private Number parseNumber(String str, String typeStr) throws InvalidConfigException {
        try {
            if (typeStr.equals("bool") || typeStr.equals("int") || typeStr.equals("str") || typeStr.startsWith("str(") ||
                typeStr.startsWith("list(") || typeStr.startsWith("tuple(") || typeStr.startsWith("set(") || typeStr.startsWith("dict(")) {
                return Integer.parseInt(str);
            } else if (typeStr.equals("float")) {
                return Double.parseDouble(str);
            } else {
                return Double.parseDouble(str);
            }
        } catch (NumberFormatException e) {
            throw new InvalidConfigException("Invalid number in domain: " + str);
        }
    }
}

